CREATE OR REPLACE TEMPORARY TABLE mp_probe AS SELECT CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= $1) THEN CAST(date_trunc('month', demo_retail.dbo.orders.order_date) AS DATE) ELSE NULL END AS event_month, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= $1 AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) > $2) THEN $3 WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= $1 AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) < $4) THEN $5 WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= $1) THEN date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) ELSE NULL END AS lag_day, CAST(demo_retail.dbo.orders.loaded_at AS DATE) AS load_epoch_day, CAST(NULL AS VARCHAR) AS batch_id, CAST(NULL AS VARCHAR) AS alt_value, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= $1) THEN $6 ELSE $7 END AS is_eligible, CASE WHEN (demo_retail.dbo.orders.order_date IS NULL) THEN $8 ELSE $9 END AS is_null_event_time, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NULL) THEN $10 ELSE $11 END AS is_null_load_time_only, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= $12 AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) < $13) THEN $14 ELSE $15 END AS is_negative_clipped, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) < $16) THEN $17 ELSE $18 END AS is_negative_lag_excluded, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= $1 AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) > $19) THEN $20 ELSE $21 END AS is_overflow, CAST($22 AS INTEGER) AS is_join_unmatched, CAST($23 AS INTEGER) AS is_base_row, CAST($24 AS INTEGER) AS is_ambiguous_base, CAST($25 AS INTEGER) AS is_compare_mismatch, CAST(NULL AS INTEGER) AS lookup_dup, CAST(NULL AS VARCHAR) AS key_hash, demo_retail.dbo.orders.loaded_at AS load_time 
FROM demo_retail.dbo.orders 
WHERE demo_retail.dbo.orders.loaded_at <= $26 OR demo_retail.dbo.orders.loaded_at IS NULL
